            // ---- How To Play + menu help ---------------------------------------------------------
            ["This part of the game is still locked. Keep progressing to reveal this help section."] = "Dieser Teil des Spiels ist noch gesperrt. Mach weiter Fortschritte, um diesen Hilfeabschnitt freizuschalten.",
            ["Welcome!"] = "Willkommen!",
            ["Basics"] = "Grundlagen",
