            ["Prestige Reset"] = "Prestige-Reset",
            ["PPO"] = "PPO",
            ["<sprite name=\"insight\" tint=1> reward formula"] = "<sprite name=\"insight\" tint=1>-Belohnungsformel",
            ["General:\n" +
                    "<b>moveInterval = max(minInterval, speedInterval x solverPacing x computePacing x agentPacing x trainingPacing)</b>\n\n" +
                    "For heavy search solvers:\n" +
                    "<b>computePacing = max(0.35, 1 - 0.11 x ComputeSpeedLevel)</b>"] =
                "Allgemein:\n" +
                "<b>moveInterval = max(minInterval, speedInterval x solverPacing x computePacing x agentPacing x trainingPacing)</b>\n\n" +
                "Für rechenintensive Such-Solver:\n" +
                "<b>computePacing = max(0.35, 1 - 0.11 x ComputeSpeedLevel)</b>",
            ["Catalyst Stack doubles merge rewards.\n\n" +
                    "<b>salvage = ceil(score x salvageShare x 0.25) x stage x globalIncome</b>\n\n" +
                    "Because runs become longer and more flexible, planning solvers and PPO also become more valuable."] =
                "Catalyst Stack verdoppelt die Merge-Belohnungen.\n\n" +
                "<b>salvage = ceil(score x salvageShare x 0.25) x stage x globalIncome</b>\n\n" +
                "Da Runs länger und flexibler werden, werden auch planende Solver und PPO wertvoller.",
            ["<b><sprite name=\"insight\" tint=1> ~= round((1 + performance x 1.25 + cycleCarry) x usage x insightMultiplier)</b>\n\n" +
                    "Performance is based on PPO score and highest block. Usage comes from Normal Mode runs and frames."] =
                "<b><sprite name=\"insight\" tint=1> ~= round((1 + performance x 1.25 + cycleCarry) x usage x insightMultiplier)</b>\n\n" +
                "Die Leistung basiert auf PPO-Punkten und Höchstblock. Die Nutzung ergibt sich aus Normalmodus-Runs und -Frames.",

            // How To Play — descriptions
            ["The core gameplay is very simple. Place blocks into one of the four stacks.\n\n" +
                    "You can merge two blocks of the same value by placing one on top of the other, earning more score and a larger in-game currency reward <sprite name=\"chips\" tint=1>.\n\n" +
                    "Always make sure there is at least one free space available, and try to keep your runs going for as long as possible. A run ends when the next block can no longer be placed anywhere."] =
                "Das Kern-Gameplay ist sehr einfach. Setze Blöcke in einen der vier Stacks.\n\n" +
                "Du kannst zwei Blöcke gleichen Werts verschmelzen, indem du einen auf den anderen setzt — das bringt mehr Punkte und eine größere Belohnung an Spielwährung <sprite name=\"chips\" tint=1>.\n\n" +
                "Achte immer darauf, mindestens einen freien Platz zu haben, und versuche, deine Runs so lange wie möglich am Laufen zu halten. Ein Run endet, wenn der nächste Block nirgends mehr platziert werden kann.",
            ["The gameplay changes early on, when algorithms begin playing instead of you. From that point forward, your job is to spend your income on upgrades that make future runs faster, longer, and more valuable."] =
                "Das Gameplay ändert sich früh, wenn Algorithmen statt dir zu spielen beginnen. Ab da ist es deine Aufgabe, dein Einkommen in Upgrades zu stecken, die künftige Runs schneller, länger und wertvoller machen.",
            ["The stage multiplier starts at 1x, increases to 5x after unlocking Agents, and reaches 24x after unlocking Modifiers. Because of this, unlocking a new layer is usually more valuable than buying another standard income upgrade."] =
                "Der Phasen-Multiplikator startet bei 1x, steigt nach dem Freischalten der Agenten auf 5x und erreicht nach dem Freischalten der Modifikatoren 24x. Deshalb ist das Freischalten einer neuen Ebene meist wertvoller als ein weiteres Standard-Einkommens-Upgrade.",
            ["Algorithms (solvers) automatically play the game for you.\n\n" +
                    "When Auto Solve is enabled, the selected solver places the blocks. If no solver is selected, the run remains Manual."] =
                "Algorithmen (Solver) spielen das Spiel automatisch für dich.\n\n" +
                "Wenn Auto-Lösen aktiv ist, setzt der gewählte Solver die Blöcke. Ist kein Solver gewählt, bleibt der Run manuell.",
            ["Each solver prioritizes different values when making decisions, so comparing them is worthwhile.\n\n" +
                    "Their behavior can be adjusted after unlocking Tuning. Tuning parameters can be modified using sliders, but their effects may also negatively impact gameplay.\n\n" +
                    "Besides search depth, the biggest difference between solvers is their speed. Solver speed can be upgraded in several places throughout the game."] =
                "Jeder Solver priorisiert bei Entscheidungen andere Werte, daher lohnt sich ein Vergleich.\n\n" +
                "Sein Verhalten lässt sich nach dem Freischalten der Justierung anpassen. Die Parameter werden mit Reglern verändert, ihre Wirkung kann das Gameplay aber auch verschlechtern.\n\n" +
                "Neben der Suchtiefe ist der größte Unterschied zwischen Solvern ihr Tempo. Das Solver-Tempo lässt sich an mehreren Stellen im Spiel verbessern.",
            ["The ultimate goal is to unlock PPO, which is a learning algorithm. It starts out weak because it doesn't understand the game's rules, so it must first be trained in Training Mode.\n\n" +
                    "Later, it becomes the gateway to Prestige and permanent progression.\n\n" +
                    "<b>The requirements to unlock it only become achievable later in the game.</b>"] =
                "Das oberste Ziel ist, PPO freizuschalten, einen lernenden Algorithmus. Er startet schwach, weil er die Spielregeln nicht kennt, und muss daher zuerst im Trainingsmodus trainiert werden.\n\n" +
                "Später wird er zum Tor zu Prestige und dauerhaftem Fortschritt.\n\n" +
                "<b>Die Voraussetzungen zum Freischalten werden erst später im Spiel erreichbar.</b>",
            ["This is the primary place to spend <sprite name=\"chips\" tint=1> during the early game.\n\n" +
                    "Here you unlock automation, speed up and expand gameplay, and increase your income generation.\n\n" +
                    "<b>Some upgrades have little impact on their own but become much stronger when combined with others.</b>"] =
                "Hier gibst du im frühen Spiel hauptsächlich <sprite name=\"chips\" tint=1> aus.\n\n" +
                "Hier schaltest du Automatisierung frei, beschleunigst und erweiterst das Gameplay und steigerst deine Einkommensproduktion.\n\n" +
                "<b>Manche Upgrades wirken allein kaum, werden aber im Zusammenspiel mit anderen viel stärker.</b>",
            ["It's recommended to purchase automation upgrades first so you can start focusing on management as soon as possible."] =
                "Es empfiehlt sich, zuerst Automatisierungs-Upgrades zu kaufen, damit du dich so früh wie möglich auf das Management konzentrieren kannst.",
            ["<b>Keep in mind that Auto Restart consumes <sprite name=\"token\" tint=1>, and cannot function without it.</b>"] =
                "<b>Beachte, dass der Auto-Neustart <sprite name=\"token\" tint=1> verbraucht und ohne sie nicht funktioniert.</b>",
            ["<b>Unlocking Agents increases the game to a 5x stage multiplier.</b>"] =
                "<b>Das Freischalten der Agenten erhöht den Phasen-Multiplikator auf 5x.</b>",
            ["Agents provide active loadout bonuses.\n\n" +
                    "Simply purchasing an Agent isn't enough to make it available, it must also be selected. By default, you can equip two Agents at once, and this limit can be increased through upgrades."] =
                "Agenten geben aktive Loadout-Boni.\n\n" +
                "Einen Agenten nur zu kaufen reicht nicht, er muss auch ausgewählt werden. Standardmäßig kannst du zwei Agenten gleichzeitig ausrüsten; dieses Limit lässt sich durch Upgrades erhöhen.",
            ["<b>The combination of equipped Agents determines which aspect of a run becomes more efficient, since most Agents improve a specific reward source instead of multiplying the entire economy.</b>"] =
                "<b>Die Kombination der ausgerüsteten Agenten bestimmt, welcher Aspekt eines Runs effizienter wird, da die meisten Agenten eine bestimmte Belohnungsquelle verbessern, statt die gesamte Wirtschaft zu multiplizieren.</b>",
            ["Some Agents have little effect on their own, but become significantly stronger when combined with other Agents and upgrades."] =
                "Manche Agenten wirken allein kaum, werden aber in Kombination mit anderen Agenten und Upgrades deutlich stärker.",
            ["Choose Agents based on what's currently limiting your progress. If runs end too quickly, prioritize stability. Once your runs are long enough, score, high-block, or merge rewards become more valuable."] =
                "Wähle Agenten danach, was deinen Fortschritt gerade begrenzt. Enden Runs zu schnell, priorisiere Stabilität. Sind deine Runs lang genug, werden Punkte-, Höchstblock- oder Merge-Belohnungen wertvoller.",
            ["<b>Unlocking Modifiers increases the game to a 24x stage multiplier.</b>"] =
                "<b>Das Freischalten der Modifikatoren erhöht den Phasen-Multiplikator auf 24x.</b>",
            ["Modifiers change the rules of future runs. They provide a higher ceiling, a more flexible board, and more tools for advanced solvers to take advantage of."] =
                "Modifikatoren ändern die Regeln künftiger Runs. Sie bieten eine höhere Obergrenze, ein flexibleres Brett und mehr Werkzeuge, die fortgeschrittene Solver nutzen können.",
            ["Some Modifiers grant actions that can be freely used during gameplay. Every Modifier can also be used in Manual Mode."] =
                "Manche Modifikatoren gewähren Aktionen, die im Spiel frei nutzbar sind. Jeder Modifikator kann auch im manuellen Modus genutzt werden.",
            ["Research is responsible for speeding up and deepening future playthroughs, and it is also where Prestige Reset becomes available.\n\n" +
                    "Here you can purchase permanent upgrades that make gameplay easier, but they require <sprite name=\"insight\" tint=1>.\n\n"] =
                "Die Forschung beschleunigt und vertieft künftige Durchläufe und ist auch der Ort, an dem der Prestige-Reset verfügbar wird.\n\n" +
                "Hier kaufst du dauerhafte Upgrades, die das Gameplay erleichtern, aber sie brauchen <sprite name=\"insight\" tint=1>.\n\n",
            ["<sprite name=\"insight\" tint=1> is generated by letting PPO play in Normal Mode.\n\n" +
                    "<b>You must perform a Prestige Reset to claim your <sprite name=\"insight\" tint=1>.</b>"] =
                "<sprite name=\"insight\" tint=1> entsteht, indem du PPO im Normalmodus spielen lässt.\n\n" +
                "<b>Du musst einen Prestige-Reset durchführen, um deinen <sprite name=\"insight\" tint=1> einzufordern.</b>",
            ["A Prestige Reset removes all accumulated <sprite name=\"chips\" tint=1>, <sprite name=\"token\" tint=1>, Upgrades, Agents, and Modifiers.\n\n" +
                    "However, your <sprite name=\"insight\" tint=1>, purchased Research, permanent PPO knowledge, and Datacenter progress are preserved."] =
                "Ein Prestige-Reset entfernt alle angesammelten <sprite name=\"chips\" tint=1>, <sprite name=\"token\" tint=1>, Upgrades, Agenten und Modifikatoren.\n\n" +
                "Dein <sprite name=\"insight\" tint=1>, gekaufte Forschung, dauerhaftes PPO-Wissen und der Rechenzentrum-Fortschritt bleiben jedoch erhalten.",
            ["Datacenter is a permanent compute layer that unlocks after your 5th Prestige Reset.\n\n" +
                    "Every upgrade here accelerates different stages of gameplay.\n\n" +
                    "This layer uses <sprite name=\"chips\" tint=1> as its currency again, meaning the production accumulated by PPO in Normal Mode is no longer lost after Prestige Reset."] =
                "Das Rechenzentrum ist eine dauerhafte Rechen-Ebene, die nach deinem 5. Prestige-Reset freigeschaltet wird.\n\n" +
                "Jedes Upgrade hier beschleunigt andere Phasen des Gameplays.\n\n" +
                "Diese Ebene nutzt wieder <sprite name=\"chips\" tint=1> als Währung, sodass die von PPO im Normalmodus angesammelte Produktion nach einem Prestige-Reset nicht mehr verloren geht.",
            ["<b>Be sure to spend your accumulated <sprite name=\"chips\" tint=1> before performing a Prestige Reset, otherwise they will be lost.</b>"] =
                "<b>Gib deine angesammelten <sprite name=\"chips\" tint=1> unbedingt vor einem Prestige-Reset aus, sonst gehen sie verloren.</b>",
            ["You can purchase Server Racks and Facility Upgrades, then allocate the resulting compute capacity however you like between passive PPO training, passive <sprite name=\"insight\" tint=1> generation, or a <sprite name=\"chips\" tint=1> income multiplier."] =
                "Du kannst Server-Racks und Anlagen-Upgrades kaufen und die entstehende Rechenkapazität beliebig zwischen passivem PPO-Training, passiver <sprite name=\"insight\" tint=1>-Erzeugung oder einem <sprite name=\"chips\" tint=1>-Einkommens-Multiplikator aufteilen.",

            // Menu help — bodies
            ["Place the blocks into one of the four stacks.\n\n" +
                "By placing two blocks with the same value on top of each other, you can merge them, earning more score and receiving a larger in-game currency <sprite name=\"chips\" tint=1> reward.\n\n" +
                "Make sure to always keep at least one free space available, and try to make your runs last as long as possible.\n\n" +
                "The gameplay changes early on, when algorithms start playing instead of you. From that point onward, your role is to purchase various upgrades and manage them.\n\n" +
                "<b>You can find details about every important game feature in Settings > How to Play menu.</b>"] =
                "Setze die Blöcke in einen der vier Stacks.\n\n" +
                "Indem du zwei Blöcke gleichen Werts aufeinandersetzt, verschmilzt du sie, erhältst mehr Punkte und eine größere Belohnung an Spielwährung <sprite name=\"chips\" tint=1>.\n\n" +
                "Halte stets mindestens einen freien Platz frei und versuche, deine Runs so lange wie möglich dauern zu lassen.\n\n" +
                "Das Gameplay ändert sich früh, wenn Algorithmen statt dir zu spielen beginnen. Ab da besteht deine Rolle darin, verschiedene Upgrades zu kaufen und zu verwalten.\n\n" +
                "<b>Details zu jeder wichtigen Spielfunktion findest du unter Einstellungen > Spielanleitung.</b>",
            ["Algorithms are responsible for playing the game automatically for you.\n\n" +
                "Each solver prioritizes different values when making decisions, so it's worth comparing them. Their behavior can be tuned once Tuning is unlocked.\n\n" +
                "The ultimate goal is to unlock PPO, which is a learning algorithm. The requirements for unlocking it can only be met later in the game."] =
                "Algorithmen spielen das Spiel automatisch für dich.\n\n" +
                "Jeder Solver priorisiert bei Entscheidungen andere Werte, daher lohnt sich ein Vergleich. Sein Verhalten lässt sich justieren, sobald die Justierung freigeschaltet ist.\n\n" +
                "Das oberste Ziel ist, PPO freizuschalten, einen lernenden Algorithmus. Die Voraussetzungen dafür sind erst später im Spiel erfüllbar.",
            ["Upgrades are the early-game progression layer based on <sprite name=\"chips\" tint=1>.\n\n" +
                "This is where you unlock automation, speed up and expand gameplay, and increase your income generation.\n\n" +
                "It's generally best to prioritize automation upgrades so you can focus on managing your run as early as possible.\n\n" +
                "<b>Keep in mind that Auto Restart consumes <sprite name=\"token\" tint=1>.</b>"] =
                "Upgrades sind die auf <sprite name=\"chips\" tint=1> basierende Fortschritts-Ebene des frühen Spiels.\n\n" +
                "Hier schaltest du Automatisierung frei, beschleunigst und erweiterst das Gameplay und steigerst deine Einkommensproduktion.\n\n" +
                "Meist ist es am besten, Automatisierungs-Upgrades zu priorisieren, damit du dich so früh wie möglich auf das Verwalten deines Runs konzentrieren kannst.\n\n" +
                "<b>Beachte, dass der Auto-Neustart <sprite name=\"token\" tint=1> verbraucht.</b>",
            ["Agents provide active loadout bonuses.\n\n" +
                "Not every owned Agent is active: the combination equipped in your slots determines which aspects of your run become more effective."] =
                "Agenten geben aktive Loadout-Boni.\n\n" +
                "Nicht jeder besessene Agent ist aktiv: Die in deinen Slots ausgerüstete Kombination bestimmt, welche Aspekte deines Runs effektiver werden.",
            ["Modifiers change the rules of future runs. They unlock new possibilities and increase your income, but they also make the board more complex.\n\n" +
                "Some Modifiers can be upgraded multiple times.\n\n" +
                "<b>Purchasing every Modifier unlocks the PPO algorithm, marking the gateway to the endgame.</b>"] =
                "Modifikatoren ändern die Regeln künftiger Runs. Sie eröffnen neue Möglichkeiten und erhöhen dein Einkommen, machen das Brett aber auch komplexer.\n\n" +
                "Manche Modifikatoren lassen sich mehrfach verbessern.\n\n" +
                "<b>Der Kauf jedes Modifikators schaltet den PPO-Algorithmus frei — das Tor zum Endgame.</b>",
            ["Research is the progression layer that unlocks the ability to Prestige Reset.\n\n" +
                "Here, you can purchase permanent upgrades that make gameplay easier and faster, but they require <sprite name=\"insight\" tint=1>.\n\n" +
                "<sprite name=\"insight\" tint=1> is generated by running the PPO algorithm in Normal Mode.\n\n" +
                "To claim your <sprite name=\"insight\" tint=1>, you must perform a Prestige Reset. You can find details in the Console."] =
                "Die Forschung ist die Fortschritts-Ebene, die den Prestige-Reset freischaltet.\n\n" +
                "Hier kaufst du dauerhafte Upgrades, die das Gameplay leichter und schneller machen, aber sie brauchen <sprite name=\"insight\" tint=1>.\n\n" +
                "<sprite name=\"insight\" tint=1> entsteht, indem du den PPO-Algorithmus im Normalmodus laufen lässt.\n\n" +
                "Um deinen <sprite name=\"insight\" tint=1> einzufordern, musst du einen Prestige-Reset durchführen. Details findest du in der Konsole.",
            ["Datacenter is a persistent compute layer that speeds up your Prestiges.\n\n" +
                "Here, <sprite name=\"chips\" tint=1> becomes the currency again, meaning the production accumulated in PPO Normal Mode is no longer wasted when you perform a Prestige Reset.\n\n" +
                "<b>Be sure to spend your accumulated <sprite name=\"chips\" tint=1> before resetting, as any unspent amount will be lost.</b>\n\n" +
                "You can purchase Server Racks and Facility Upgrades, then allocate the resulting compute capacity however you like: to passive PPO training, passive <sprite name=\"insight\" tint=1> generation, or a <sprite name=\"chips\" tint=1> production multiplier."] =
                "Das Rechenzentrum ist eine dauerhafte Rechen-Ebene, die deine Prestiges beschleunigt.\n\n" +
                "Hier wird wieder <sprite name=\"chips\" tint=1> zur Währung, sodass die im PPO-Normalmodus angesammelte Produktion bei einem Prestige-Reset nicht mehr verschwendet wird.\n\n" +
                "<b>Gib deine angesammelten <sprite name=\"chips\" tint=1> unbedingt vor dem Reset aus, da nicht ausgegebene Beträge verloren gehen.</b>\n\n" +
                "Du kannst Server-Racks und Anlagen-Upgrades kaufen und die entstehende Rechenkapazität beliebig aufteilen: auf passives PPO-Training, passive <sprite name=\"insight\" tint=1>-Erzeugung oder einen <sprite name=\"chips\" tint=1>-Produktions-Multiplikator.",
            ["Here you can see detailed data on how your runs perform during the current Prestige cycle.\n\n" +
                "You can view your highest score, best median performance, average run duration, and results for each solver.\n\n" +
                "<b>Measure how a new algorithm, Tuning, or any other modification affects your performance.</b>"] =
                "Hier siehst du detaillierte Daten dazu, wie deine Runs im aktuellen Prestige-Zyklus abschneiden.\n\n" +
                "Du kannst deinen höchsten Punktestand, die beste mediane Leistung, die durchschnittliche Run-Dauer und die Ergebnisse je Solver einsehen.\n\n" +
                "<b>Miss, wie ein neuer Algorithmus, eine Justierung oder eine andere Änderung deine Leistung beeinflusst.</b>",
            ["Here you can track your best results achieved throughout your playtime, along with a summary of your overall progress. You can also see which goals you have already completed.\n\n" +
                "<b>Some milestones grant permanent rewards or cosmetic unlocks.</b>"] =
                "Hier verfolgst du deine besten über die Spielzeit erreichten Ergebnisse samt einer Zusammenfassung deines Gesamtfortschritts. Du siehst auch, welche Ziele du bereits erreicht hast.\n\n" +
                "<b>Manche Meilensteine gewähren dauerhafte Belohnungen oder kosmetische Freischaltungen.</b>",

            // ---- Dynamically-composed labels + datacenter allocation bodies ----------------------
            ["reach Prestige"] = "erreiche Prestige",
            ["rack FLOPS"] = "Rack-FLOPS",
            ["TPU / Fabric"] = "TPU / Fabric",
            ["Effect"] = "Wirkung",
            ["Level"] = "Stufe",
            ["Completed goals"] = "Erfüllte Ziele",
            ["Best run"] = "Bester Run",
            ["moves"] = "Züge",
            ["manual"] = "manuell",
            ["Restart in"] = "Neustart in",
            ["Equipped Agents"] = "Ausgerüstete Agenten",
            ["Active Modifiers"] = "Aktive Modifikatoren",
            ["Buy all Facility Upgrades"] = "Kaufe alle Anlagen-Upgrades",
            ["Offline cap"] = "Offline-Cap",
            ["Offline efficiency"] = "Offline-Effizienz",
            ["New-high learning"] = "Höchstblock-Lernen",
            ["Survival shaping"] = "Überlebens-Formung",
            ["PPO Normal mode at"] = "PPO-Normalmodus bei",
            ["Start with"] = "Beginne mit",
            ["cycle frames"] = "Zyklus-Frames",
            ["frames retained"] = "Frames behalten",
            ["training: +0 chips"] = "Training: +0 Chips",
            ["Pickaxe"] = "Spitzhacke",
            ["Scrubbed"] = "Entfernt",
            ["Merge"] = "Merge",
            ["Combo"] = "Combo",
            ["Spent"] = "Ausgegeben",
            ["Passively trains PPO, which counts as Training Mode frames. <b>PPO learns permanently even when not in use.</b>"] =
                "Trainiert PPO passiv, was als Trainingsmodus-Frames zählt. <b>PPO lernt dauerhaft, auch wenn es nicht genutzt wird.</b>",
            ["Passively generates <sprite name=\"insight\" tint=1> at any stage of the game, so using PPO in Normal Mode is no longer required for that."] =
                "Erzeugt passiv <sprite name=\"insight\" tint=1> in jeder Spielphase, sodass PPO im Normalmodus dafür nicht mehr nötig ist.",
            ["It gives an income multiplier to everything that produces <sprite name=\"chips\" tint=1> in any form."] =
                "Es gibt allem, was in irgendeiner Form <sprite name=\"chips\" tint=1> erzeugt, einen Einkommens-Multiplikator.",
        };
